/**
 * Vercel Serverless Function (Node.js runtime) — YouTube transcript fetcher.
 *
 * Uses the `youtube-transcript` npm package on the server side with
 * a CONSENT cookie to help bypass YouTube's bot detection.
 *
 * COMPLIANCE NOTE: This endpoint fetches auto-generated captions via
 * unofficial means (youtube-transcript package / InnerTube). This may
 * violate YouTube's Terms of Service. Risk is low at small scale but
 * increases with traffic. Fallback: manual transcript paste in the UI.
 *
 * Usage: GET /api/transcript?videoId=<id>&lang=<en>
 * Returns: JSON with transcript lines
 */

// Consent cookie to help bypass YouTube's bot wall
const CONSENT_COOKIE =
  'CONSENT=PENDING+987; SOCS=CAISNQgDEitib3FfaWRlbnRpdHlmcm9udGVuZHVpc2VydmVyXzIwMjMwODI5LjA3X3AxGgJlbiACGgYIgJnSmgY';

// ── Per-IP rate limiter (per serverless instance, best-effort) ──
const RATE_LIMIT_WINDOW_MS = 60_000;
const RATE_LIMIT_MAX = 20;
const rateBuckets = new Map<string, number[]>();

function isRateLimited(ip: string): boolean {
  const now = Date.now();
  const cutoff = now - RATE_LIMIT_WINDOW_MS;
  if (rateBuckets.size >= 5000) {
    for (const [k, v] of rateBuckets) {
      if (v.length === 0 || v[v.length - 1] <= cutoff) rateBuckets.delete(k);
    }
  }
  let hits = rateBuckets.get(ip);
  if (!hits) { hits = []; rateBuckets.set(ip, hits); }
  while (hits.length > 0 && hits[0] <= cutoff) hits.shift();
  if (hits.length >= RATE_LIMIT_MAX) return true;
  hits.push(now);
  return false;
}

// Origins allowed to call this endpoint via CORS.
const ALLOWED_ORIGINS = [
  'https://app.echo-learn.uk',
  'https://echo-learn.uk',
  'http://localhost:5173',
  'http://localhost:4173',
  'http://127.0.0.1:5173',
];

function resolveOrigin(origin: string | undefined): string | null {
  if (!origin) return null;
  if (ALLOWED_ORIGINS.includes(origin)) return origin;
  if (origin.endsWith('.vercel.app')) return origin; // Vercel preview deployments
  return null;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export default async function handler(req: any, res: any): Promise<void> {
  // CORS headers (restricted to the app's known origins)
  const allowed = resolveOrigin(req.headers?.origin as string | undefined);
  if (allowed) res.setHeader('Access-Control-Allow-Origin', allowed);
  res.setHeader('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') {
    res.status(204).end();
    return;
  }

  // Rate limit per IP
  const ip = (req.headers?.['x-forwarded-for'] as string)?.split(',')[0]?.trim()
    || (req.headers?.['x-real-ip'] as string)
    || (req.socket?.remoteAddress as string)
    || 'unknown';
  if (isRateLimited(ip)) {
    res.status(429).json({ error: 'Rate limit exceeded. Please slow down.' });
    return;
  }

  const videoId = req.query?.videoId;
  const lang = (req.query?.lang as string) || 'en';

  if (!videoId || typeof videoId !== 'string') {
    res.status(400).json({ error: 'Missing videoId parameter' });
    return;
  }

  try {
    const { YoutubeTranscript } = await import('youtube-transcript');

    // Custom fetch that adds CONSENT cookie to all YouTube requests
    const customFetch = (url: string | URL | Request, init?: RequestInit) => {
      const headers = new Headers(init?.headers);
      headers.set('Cookie', CONSENT_COOKIE);
      // Also set a realistic browser UA as fallback
      if (!headers.has('User-Agent')) {
        headers.set(
          'User-Agent',
          'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36',
        );
      }
      return fetch(url, { ...init, headers });
    };

    const result = await YoutubeTranscript.fetchTranscript(videoId, {
      lang,
      fetch: customFetch,
    });

    if (!result || result.length === 0) {
      res.status(404).json({ error: 'No transcript found for this video' });
      return;
    }

    // Transform to our TranscriptLine format
    const lines = result.map(
      (item: { text: string; offset: number; duration: number }, i: number) => ({
        id: `yt_${i + 1}`,
        start: item.offset > 1000 ? item.offset / 1000 : item.offset,
        end:
          (item.offset > 1000 ? item.offset / 1000 : item.offset) +
          (item.duration > 1000 ? item.duration / 1000 : item.duration),
        text: item.text,
      }),
    );

    res.status(200).json({
      lines,
      language: result[0]?.lang ?? lang,
      isAutoGenerated: true,
    });
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Unknown error';
    console.error('[transcript] Error:', message);
    res.status(500).json({ error: message });
  }
}
